import React from 'react';

const MovieCard = ({ movie, delay = 0 }) => {
  const matchScore = Math.floor(Math.random() * (99 - 85 + 1)) + 85;

  return (
    <div className="flex-none w-52 group cursor-pointer transition-all duration-300">
      <div className="relative aspect-[2/3] rounded-xl overflow-hidden bg-surface-container shadow-2xl transition-all duration-300 group-hover:translate-y-[-8px]">
        <img 
          className="w-full h-full object-cover" 
          alt={movie.title} 
          src={movie.poster || 'https://via.placeholder.com/500x750?text=No+Poster'} 
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex flex-col justify-end p-4">
          <div className="bg-tertiary-container/90 backdrop-blur-sm rounded-lg p-3 transform translate-y-4 group-hover:translate-y-0 transition-transform">
            <p className="text-[10px] font-bold text-on-tertiary-container uppercase tracking-tighter mb-1">AI Insight</p>
            <p className="text-[11px] leading-tight text-white/90">
              {movie.overview ? movie.overview.substring(0, 100) + '...' : "We've identified a strong alignment with your recent cinematic interests."}
            </p>
          </div>
        </div>
        {movie.rating && (
           <div className="absolute top-2 right-2">
            <span className="bg-surface/80 backdrop-blur-md px-2 py-0.5 rounded text-[10px] font-bold text-secondary">{Math.round(movie.rating * 10)}% MATCH</span>
          </div>
        )}
      </div>
      <div className="mt-4 px-1">
        <h4 className="font-bold text-sm group-hover:text-primary transition-colors truncate">{movie.title}</h4>
        <div className="flex items-center gap-2 mt-1">
          <span className="text-[10px] font-bold text-secondary-fixed-dim">{matchScore}% MATCH</span>
          <span className="text-[10px] text-neutral-500">{movie.year || '2024'}</span>
        </div>
      </div>
    </div>
  );
};

export default MovieCard;
